mapper.select:
SELECT 
    FROM session
where id = #{id}
    and tenant_id = #{tenantId}
    and is_deleted = 0

select 
    from session
where tenant_id = #{tenantId}
    and user_id = #{userId}
    and is_deleted = 0
order by last_message_at desc NULLS LAST, gmt_create desc

mapper.update:
UPDATE session
SET title = #{title},
    gmt_modified = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND tenant_id = #{tenantId}
  AND is_deleted = 0

UPDATE session
SET is_deleted = 1,
    gmt_modified = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND tenant_id = #{tenantId}
  AND is_deleted = 0

UPDATE session
SET last_message_at = #{lastMessageAt},
    gmt_modified = CURRENT_TIMESTAMP
WHERE id = #{sessionId}
  AND user_id = #{userId}
  AND is_deleted = 0
